#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>

#define RADIUS 7
#define BLOCK_SIZE 256

__global__ void process_kernel(int* a, int* b, int length, int pad_size) {
    int block_id = blockIdx.x;
    int i = block_id * BLOCK_SIZE;

    if (i >= length) return;

    int temp[BLOCK_SIZE + 2 * RADIUS];

    // Load data into temp
    for (int j = 0; j < BLOCK_SIZE; j++) {
        int gindex = i + j;
        if (gindex >= length) break;
        temp[j + RADIUS] = a[gindex];
        if (RADIUS > j) {
            temp[j] = (RADIUS > gindex) ? 0 : a[gindex - RADIUS];
            temp[j + RADIUS + BLOCK_SIZE] = (gindex + BLOCK_SIZE < pad_size) ? a[gindex + BLOCK_SIZE] : 0;
        }
    }

    // Compute sum over radius
    for (int j = 0; j < BLOCK_SIZE; j++) {
        int gindex = i + j;
        if (gindex >= length) break;
        int result = 0;
        for (int offset = -RADIUS; offset <= RADIUS; offset++) {
            result += temp[j + RADIUS + offset];
        }
        b[gindex] = result;
    }
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }
  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length;
  int pad_size = (length + RADIUS);

  int* a_host = (int *)malloc(pad_size * sizeof(int));
  int* b_host = (int *)malloc(size * sizeof(int));

  for (int i = 0; i < length + RADIUS; i++) a_host[i] = i;

  int* a_dev = NULL;
  int* b_dev = NULL;
  cudaMalloc(&a_dev, pad_size * sizeof(int));
  cudaMalloc(&b_dev, size * sizeof(int));

  cudaMemcpy(a_dev, a_host, pad_size * sizeof(int), cudaMemcpyHostToDevice);

  int num_blocks = (length + BLOCK_SIZE - 1) / BLOCK_SIZE;

  cudaEvent_t start, end;
  cudaEventCreate(&start);
  cudaEventCreate(&end);

  cudaEventRecord(start);

  for (int i = 0; i < repeat; i++) {
    process_kernel<<<num_blocks, 1>>>(a_dev, b_dev, length, pad_size);
  }

  cudaEventRecord(end);
  cudaEventSynchronize(end);

  float elapsed_time = 0;
  cudaEventElapsedTime(&elapsed_time, start, end);
  printf("Average kernel execution time: %f (s)\n", (elapsed_time * 1e-3f) / repeat);

  cudaMemcpy(b_host, b_dev, size * sizeof(int), cudaMemcpyDeviceToHost);

  bool ok = true;
  for (int i = 0; 2 * RADIUS > i; i++) {
    int s = 0;
    for (int j = i; i + 2 * RADIUS >= j; j++)
      s += RADIUS > j ? 0 : (a_host[j] - RADIUS);
    if (s != b_host[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b_host[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2 * RADIUS; length > i; i++) {
    int s = 0;
    for (int j = i - RADIUS; i + RADIUS >= j; j++)
      s = s + (a_host[j]);
    if (b_host[i] != s) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b_host[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  cudaFree(a_dev);
  cudaFree(b_dev);
  cudaEventDestroy(start);
  cudaEventDestroy(end);

